1	interface QuoteItem {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteInput {
9	  customer: { yearsWithMHPCO: number };
10	  items: QuoteItem[];
11	  contractIndex?: number;
12	  firstInsurance?: boolean;
13	  followUp?: boolean;
14	}
15	
16	const PROCESSING_FEE = 5;
17	
18	const BASE_PREMIUMS: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const BLOCK_SIZE = 3;
28	const BLOCK_PREMIUM = 60;
29	
30	const CURSE_SURCHARGE_RATE = 0.5;
31	
32	const HIGH_ENCHANTMENT_THRESHOLD = 5;
33	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
34	
35	function countByType(items: QuoteItem[]): Map<string, number> {
36	  const counts = new Map<string, number>();
37	  for (const item of items) {
38	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
39	  }
40	  return counts;
41	}
42	
43	function priceGroup(type: string, count: number): number {
44	  return count === BLOCK_SIZE ? BLOCK_PREMIUM : BASE_PREMIUMS[type] * count;
45	}
46	
47	function surchargeFor(
48	  items: QuoteItem[],
49	  applies: (item: QuoteItem) => boolean,
50	  rate: number,
51	): number {
52	  let surcharge = 0;
53	  for (const item of items) {
54	    if (applies(item)) {
55	      surcharge += BASE_PREMIUMS[item.type] * rate;
56	    }
57	  }
58	  return surcharge;
59	}
60	
61	function curseSurchargeFor(items: QuoteItem[]): number {
62	  return surchargeFor(items, (item) => item.cursed === true, CURSE_SURCHARGE_RATE);
63	}
64	
65	function highEnchantmentSurchargeFor(items: QuoteItem[]): number {
66	  return surchargeFor(
67	    items,
68	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
69	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
70	  );
71	}
72	
73	function policyBasePremiumFor(items: QuoteItem[]): number {
74	  const countsByType = countByType(items);
75	
76	  let basePremium = 0;
77	  for (const [type, count] of countsByType) {
78	    basePremium += priceGroup(type, count);
79	  }
80	  return basePremium;
81	}
82	
83	function itemSurchargesFor(items: QuoteItem[]): number {
84	  return curseSurchargeFor(items) + highEnchantmentSurchargeFor(items);
85	}
86	
87	const LOYALTY_YEARS_THRESHOLD = 2;
88	
89	// Signed rates of the policy base premium: discounts are negative, surcharges positive.
90	const LOYALTY_DISCOUNT_RATE = -0.2;
91	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
92	const FOLLOW_UP_DISCOUNT_RATE = -0.15;
93	
94	function policyWideModifiersFor(input: QuoteInput, policyBasePremium: number): number {
95	  const activeRates = [
96	    { active: input.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD, rate: LOYALTY_DISCOUNT_RATE },
97	    { active: input.firstInsurance, rate: FIRST_INSURANCE_SURCHARGE_RATE },
98	    { active: input.followUp, rate: FOLLOW_UP_DISCOUNT_RATE },
99	  ];
100	
101	  let total = 0;
102	  for (const { active, rate } of activeRates) {
103	    if (active) {
104	      total += policyBasePremium * rate;
105	    }
106	  }
107	  return total;
108	}
109	
110	export function quote(input: QuoteInput): number {
111	  const policyBasePremium = policyBasePremiumFor(input.items);
112	  const premiumWithSurcharges = policyBasePremium + itemSurchargesFor(input.items);
113	  const policyWideModifiers = policyWideModifiersFor(input, policyBasePremium);
114	  return Math.ceil(premiumWithSurcharges + policyWideModifiers + PROCESSING_FEE);
115	}
116	
117	interface ClaimPolicy {
118	  items: QuoteItem[];
119	}
120	
121	interface ClaimDamage {
122	  itemType: string;
123	  amount: number;
124	}
125	
126	interface ClaimIncident {
127	  cause: string;
128	  damages: ClaimDamage[];
129	}
130	
131	interface ClaimResult {
132	  payout: number;
133	  remainingCap: number;
134	}
135	
136	const DEDUCTIBLE = 100;
137	const CAP_MULTIPLIER = 2;
138	
139	const INSURANCE_VALUES: Record<string, number> = {
140	  sword: 1000,
141	  amulet: 600,
142	  staff: 800,
143	  potion: 400,
144	  rune: 250,
145	  moonstone: 250,
146	};
147	
148	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
149	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
150	
151	function isHighlyEnchanted(item: QuoteItem | undefined): boolean {
152	  return (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
153	}
154	
155	function reimbursementFor(damage: ClaimDamage, policy: ClaimPolicy): number {
156	  const insuredItem = policy.items.find((item) => item.type === damage.itemType);
157	  if (isHighlyEnchanted(insuredItem)) {
158	    return damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
159	  }
160	  return damage.amount;
161	}
162	
163	function payoutFor(incident: ClaimIncident, policy: ClaimPolicy): number {
164	  let payout = 0;
165	  for (const damage of incident.damages) {
166	    payout += reimbursementFor(damage, policy) - DEDUCTIBLE;
167	  }
168	  return payout;
169	}
170	
171	function capFor(policy: ClaimPolicy): number {
172	  let insuranceTotal = 0;
173	  for (const item of policy.items) {
174	    insuranceTotal += INSURANCE_VALUES[item.type];
175	  }
176	  return CAP_MULTIPLIER * insuranceTotal;
177	}
178	
179	export function claim(policy: ClaimPolicy, incident: ClaimIncident): ClaimResult {
180	  const payout = payoutFor(incident, policy);
181	  const cap = capFor(policy);
182	  return { payout, remainingCap: cap - payout };
183	}
